import{_ as t,o,c as i,ag as a}from"./chunks/framework.BqfgOMAh.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/faq/index.md","filePath":"en/faq/index.md"}'),n={name:"en/faq/index.md"};function s(r,e,l,c,d,h){return o(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="connection-issues" tabindex="-1">Connection Issues <a class="header-anchor" href="#connection-issues" aria-label="Permalink to &quot;Connection Issues&quot;">​</a></h2><h3 id="nexusflow-keeps-showing-disconnected-after-launch" tabindex="-1">NexusFlow keeps showing &quot;disconnected&quot; after launch? <a class="header-anchor" href="#nexusflow-keeps-showing-disconnected-after-launch" aria-label="Permalink to &quot;NexusFlow keeps showing &quot;disconnected&quot; after launch?&quot;">​</a></h3><p>NexusFlow communicates with UE via a Named Pipe and supports <strong>any startup order</strong> — whether you launch NexusFlow or the UE Editor first, both sides will automatically discover each other and establish a connection.</p><p>If the connection still fails, check the following:</p><ul><li><strong>Version mismatch</strong>: The NexusFlow desktop app and UE plugin must be compatible versions. Make sure both are updated to the latest release</li><li>Is the NexusFlow plugin enabled in your UE project? (Edit &gt; Plugins)</li><li>Could a firewall or security software be blocking communication?</li><li>Is another NexusFlow instance already running?</li></ul><div class="tip custom-block"><p class="custom-block-title">Version matching</p><p>If you recently updated the NexusFlow desktop app, update the UE plugin to the corresponding version as well. Version mismatches are a common cause of connection failures.</p></div><h3 id="do-i-need-to-restart-nexusflow-after-restarting-ue-or-switching-projects" tabindex="-1">Do I need to restart NexusFlow after restarting UE or switching projects? <a class="header-anchor" href="#do-i-need-to-restart-nexusflow-after-restarting-ue-or-switching-projects" aria-label="Permalink to &quot;Do I need to restart NexusFlow after restarting UE or switching projects?&quot;">​</a></h3><p><strong>No.</strong> NexusFlow has a built-in auto-reconnect mechanism:</p><ul><li>When UE shuts down or switches projects, the connection drops temporarily</li><li>NexusFlow automatically waits for UE to reconnect</li><li>The connection typically restores within seconds after UE finishes starting</li></ul><p>Just restart UE — NexusFlow handles the reconnection automatically.</p><h2 id="ai-models" tabindex="-1">AI Models <a class="header-anchor" href="#ai-models" aria-label="Permalink to &quot;AI Models&quot;">​</a></h2><h3 id="model-validation-failed-after-adding-it" tabindex="-1">Model validation failed after adding it? <a class="header-anchor" href="#model-validation-failed-after-adding-it" aria-label="Permalink to &quot;Model validation failed after adding it?&quot;">​</a></h3><p>Model validation sends a test request to the AI provider. Common reasons for failure:</p><table tabindex="0"><thead><tr><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td>Incorrect or expired API Key</td><td>Double-check the key; confirm it&#39;s still valid</td></tr><tr><td>Cannot reach the API endpoint</td><td>Check your network; consider whether a proxy is needed</td></tr><tr><td>Wrong model identifier</td><td>Verify the exact spelling, e.g., <code>gpt-5.4</code> not <code>gpt54</code></td></tr><tr><td>Custom Provider misconfigured</td><td>Confirm the API URL and communication protocol match</td></tr></tbody></table><h3 id="ai-response-cuts-off-or-there-s-no-response-at-all" tabindex="-1">AI response cuts off or there&#39;s no response at all? <a class="header-anchor" href="#ai-response-cuts-off-or-there-s-no-response-at-all" aria-label="Permalink to &quot;AI response cuts off or there&#39;s no response at all?&quot;">​</a></h3><p>If the AI stops mid-reply or never responds, possible causes include:</p><ul><li><strong>Insufficient account balance</strong> — Check your provider&#39;s billing page</li><li><strong>Rate limiting</strong> — Too many requests in a short period; wait and try again</li><li><strong>Unstable network</strong> — AI responses stream in real time; network hiccups can interrupt the flow</li><li><strong>Max Tokens set too low</strong> — Increase the Max Tokens value (at least 4096 is recommended)</li></ul><div class="tip custom-block"><p class="custom-block-title">Retrying</p><p>After an interruption, simply resend your message or type &quot;continue&quot; to prompt the AI to pick up where it left off.</p></div><h3 id="is-max-tokens-required-for-anthropic-claude-models" tabindex="-1">Is Max Tokens required for Anthropic (Claude) models? <a class="header-anchor" href="#is-max-tokens-required-for-anthropic-claude-models" aria-label="Permalink to &quot;Is Max Tokens required for Anthropic (Claude) models?&quot;">​</a></h3><p>Yes. The Anthropic Messages API <strong>requires</strong> a Max Tokens parameter — this is part of Anthropic&#39;s specification.</p><ul><li>Always set Max Tokens when adding an Anthropic model</li><li>Recommended value: <strong>4096</strong> or higher</li><li>Omitting it will cause API calls to fail</li></ul><div class="warning custom-block"><p class="custom-block-title">Required field</p><p>When using the Anthropic Messages API protocol — including Custom Providers with this protocol selected — Max Tokens is mandatory. See <a href="/NexusFlow/en/guide/settings">Settings - AI Models</a> for details.</p></div><h3 id="the-ai-replies-in-the-wrong-language" tabindex="-1">The AI replies in the wrong language? <a class="header-anchor" href="#the-ai-replies-in-the-wrong-language" aria-label="Permalink to &quot;The AI replies in the wrong language?&quot;">​</a></h3><p>The AI response language can be configured independently of the interface language:</p><ul><li>Go to <strong>Settings &gt; Agent Configuration &gt; Response Language</strong></li><li>The default is &quot;Follow interface language&quot;</li><li>If the UI is in English but you want Chinese replies, manually select &quot;简体中文&quot; here</li></ul><h3 id="which-ai-providers-are-supported-can-i-use-local-models" tabindex="-1">Which AI providers are supported? Can I use local models? <a class="header-anchor" href="#which-ai-providers-are-supported-can-i-use-local-models" aria-label="Permalink to &quot;Which AI providers are supported? Can I use local models?&quot;">​</a></h3><p>NexusFlow includes built-in support for:</p><ul><li><strong>OpenAI</strong> — GPT series</li><li><strong>Anthropic</strong> — Claude series</li><li><strong>Google Gemini</strong> — Gemini series</li><li><strong>DeepSeek</strong> — DeepSeek series</li><li><strong>Zhipu GLM</strong> — GLM series</li><li><strong>MiniMax</strong> — MiniMax series</li><li><strong>Qwen</strong> — Qwen series</li><li><strong>Kimi</strong> — Kimi series</li></ul><p>Through <strong>Custom Provider</strong>, you can connect any service compatible with the OpenAI / Anthropic / Gemini API, including locally hosted models:</p><ul><li><a href="https://ollama.ai/" target="_blank" rel="noreferrer">Ollama</a></li><li><a href="https://lmstudio.ai/" target="_blank" rel="noreferrer">LM Studio</a></li><li>Any other OpenAI-compatible API service</li></ul><p>Just enter the API URL and select the matching communication protocol in the Custom Provider form.</p><h2 id="blueprint-operations" tabindex="-1">Blueprint Operations <a class="header-anchor" href="#blueprint-operations" aria-label="Permalink to &quot;Blueprint Operations&quot;">​</a></h2><h3 id="can-i-stop-the-ai-while-it-s-modifying-a-blueprint" tabindex="-1">Can I stop the AI while it&#39;s modifying a Blueprint? <a class="header-anchor" href="#can-i-stop-the-ai-while-it-s-modifying-a-blueprint" aria-label="Permalink to &quot;Can I stop the AI while it&#39;s modifying a Blueprint?&quot;">​</a></h3><p><strong>Text generation can be stopped; tool operations cannot.</strong></p><ul><li>✅ While the AI is writing a text reply → click the stop button to interrupt</li><li>❌ While the AI is executing a tool operation (e.g., modifying a Blueprint) → you&#39;ll see a message: &quot;Tool is executing, cannot interrupt&quot;</li></ul><p>You&#39;ll need to wait for the current tool operation to finish before taking further action.</p><h3 id="ue-quick-menu-doesn-t-respond-when-clicked" tabindex="-1">UE Quick Menu doesn&#39;t respond when clicked? <a class="header-anchor" href="#ue-quick-menu-doesn-t-respond-when-clicked" aria-label="Permalink to &quot;UE Quick Menu doesn&#39;t respond when clicked?&quot;">​</a></h3><p>The Quick Menu depends on a live connection between NexusFlow and UE. If nothing happens:</p><ol><li>Confirm NexusFlow is running</li><li>Check whether the status bar at the bottom of the sidebar shows a 🟢 green connection indicator</li><li>If disconnected, see <a href="./troubleshooting#cannot-connect-to-ue-editor">Cannot connect to UE</a> for troubleshooting steps</li></ol><p><strong>Note about the Level Editor Toolbar button</strong>: When NexusFlow is not running, clicking this button shows a notification with download links instead of opening the sidebar. This is by design — it helps new users who installed the UE plugin but haven&#39;t installed the desktop app yet.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisite</p><p>All Quick Menu AI operations (right-click menus and Blueprint toolbar buttons) require NexusFlow to be connected to UE.</p></div><h3 id="the-ai-says-it-can-t-find-a-blueprint-node" tabindex="-1">The AI says it can&#39;t find a Blueprint node? <a class="header-anchor" href="#the-ai-says-it-can-t-find-a-blueprint-node" aria-label="Permalink to &quot;The AI says it can&#39;t find a Blueprint node?&quot;">​</a></h3><p>The AI needs up-to-date Blueprint context before it can operate. Verify the following:</p><ol><li><strong>The target Blueprint is open</strong> — double-click the Blueprint asset in UE</li><li><strong>UE is connected</strong> — the status bar should show a green indicator</li></ol><p>Context syncs automatically — you don&#39;t need to tell the AI which Blueprint you&#39;re editing. If the AI still can&#39;t find the node, try reopening the Blueprint or describing the target node more explicitly in the chat.</p><h2 id="settings-configuration" tabindex="-1">Settings &amp; Configuration <a class="header-anchor" href="#settings-configuration" aria-label="Permalink to &quot;Settings &amp; Configuration&quot;">​</a></h2><h3 id="is-my-api-key-safe-where-is-it-stored" tabindex="-1">Is my API Key safe? Where is it stored? <a class="header-anchor" href="#is-my-api-key-safe-where-is-it-stored" aria-label="Permalink to &quot;Is my API Key safe? Where is it stored?&quot;">​</a></h3><p>API Keys are <strong>encrypted</strong> and stored locally:</p><ul><li>Encrypted file location: <code>%APPDATA%/cn.nexusflow.desktop/secrets.enc</code></li><li>The settings file <code>settings.json</code> does <strong>not</strong> contain plaintext API Keys</li><li>All keys are stored locally — <strong>nothing is uploaded to any server</strong></li></ul><h3 id="where-are-the-config-files-how-do-i-reset-settings" tabindex="-1">Where are the config files? How do I reset settings? <a class="header-anchor" href="#where-are-the-config-files-how-do-i-reset-settings" aria-label="Permalink to &quot;Where are the config files? How do I reset settings?&quot;">​</a></h3><p>NexusFlow stores its configuration at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%/cn.nexusflow.desktop/</span></span>
<span class="line"><span>├── settings.json    # Settings (model configs, appearance, hotkeys, etc.)</span></span>
<span class="line"><span>├── secrets.enc      # Encrypted API Keys</span></span>
<span class="line"><span>└── logs/            # Log files</span></span></code></pre></div><p><strong>To reset everything</strong>: Delete the entire <code>%APPDATA%/cn.nexusflow.desktop/</code> directory and restart NexusFlow. It will restore default settings and re-launch the first-run setup wizard.</p><div class="danger custom-block"><p class="custom-block-title">Caution</p><p>Resetting will erase all AI model configurations and API Keys. You&#39;ll need to set them up again.</p></div><h3 id="global-hotkey-changes-don-t-take-effect" tabindex="-1">Global hotkey changes don&#39;t take effect? <a class="header-anchor" href="#global-hotkey-changes-don-t-take-effect" aria-label="Permalink to &quot;Global hotkey changes don&#39;t take effect?&quot;">​</a></h3><p>Global hotkeys must be registered with the operating system after changes. If they&#39;re not working:</p><ol><li>Check for conflicts with other applications&#39; hotkeys</li><li>Try a different key combination</li><li><strong>Restart NexusFlow</strong> to apply the new hotkeys</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If hotkeys stop working entirely, go to Settings &gt; Hotkeys and click &quot;Reset to Default.&quot;</p></div><h2 id="performance-compatibility" tabindex="-1">Performance &amp; Compatibility <a class="header-anchor" href="#performance-compatibility" aria-label="Permalink to &quot;Performance &amp; Compatibility&quot;">​</a></h2><h3 id="operations-on-large-blueprints-are-slow" tabindex="-1">Operations on large Blueprints are slow? <a class="header-anchor" href="#operations-on-large-blueprints-are-slow" aria-label="Permalink to &quot;Operations on large Blueprints are slow?&quot;">​</a></h3><p>When working with large Blueprints (many nodes), NexusFlow needs to:</p><ol><li>Read the Blueprint&#39;s full data</li><li>Convert and send it to the AI</li><li>Wait for the AI to analyze and generate instructions</li><li>Execute the operations in UE</li></ol><p>Each step takes time, and larger Blueprints naturally take longer. This is expected behavior during the Beta phase; performance will continue to improve in future releases.</p><h3 id="which-ue-versions-are-supported" tabindex="-1">Which UE versions are supported? <a class="header-anchor" href="#which-ue-versions-are-supported" aria-label="Permalink to &quot;Which UE versions are supported?&quot;">​</a></h3><p>NexusFlow supports <strong>UE 5.6</strong> and <strong>UE 5.7</strong>.</p><ul><li>✅ UE 5.7: Full support</li><li>✅ UE 5.6: Full support</li><li>❌ UE 5.5 and earlier: Not supported (requires ONNX Runtime 1.20+ for RAG embeddings, available in UE 5.6+)</li><li>❌ UE 4.x: Not supported</li></ul><div class="warning custom-block"><p class="custom-block-title">Engine Version</p><p>NexusFlow requires UE 5.6 or 5.7. Earlier versions lack the ONNX Runtime version needed for the RAG embedding model. If ONNX Runtime is unavailable, RAG search will fall back to FTS5 full-text search with reduced accuracy.</p></div><h3 id="is-macos-supported" tabindex="-1">Is macOS supported? <a class="header-anchor" href="#is-macos-supported" aria-label="Permalink to &quot;Is macOS supported?&quot;">​</a></h3><p>Currently, only <strong>Windows 10/11</strong> is supported.</p><p>macOS support is on the roadmap, but OS-level restrictions (App Sandbox limitations on inter-process communication) require additional work to resolve.</p><h2 id="more-help" tabindex="-1">More Help <a class="header-anchor" href="#more-help" aria-label="Permalink to &quot;More Help&quot;">​</a></h2><p>If the answers above didn&#39;t resolve your issue:</p><ul><li>Check the <a href="./troubleshooting">Troubleshooting Guide</a> for detailed diagnostic steps</li><li>Submit a bug report on <a href="https://github.com/maxzhao/NexusFlow/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li></ul>`,74)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
